import{f as o,D as i,o as e,c as h,k as a,a as n,b as g,w as r,G as l,a5 as s,a2 as c}from"./chunks/framework.DHYrF-q6.js";const I=JSON.parse('{"title":"LLM 编排框架生态对比","description":"","frontmatter":{},"headers":[],"relativePath":"ai-application/langchain/ecosystem.md","filePath":"ai-application/langchain/ecosystem.md","lastUpdated":1780924715000}'),u={name:"ai-application/langchain/ecosystem.md"};function L(A,t,p,m,C,q){const d=i("Mermaid");return e(),h("div",null,[t[1]||(t[1]=a("h1",{id:"llm-编排框架生态对比",tabindex:"-1"},[n("LLM 编排框架生态对比 "),a("a",{class:"header-anchor",href:"#llm-编排框架生态对比","aria-label":'Permalink to "LLM 编排框架生态对比"'},"​")],-1)),t[2]||(t[2]=a("blockquote",null,[a("p",null,[a("strong",null,"创建日期："),n(" 2026-06-06 "),a("strong",null,"前置知识："),n(" LangChain 入门、Agent 框架")])],-1)),t[3]||(t[3]=a("hr",null,null,-1)),t[4]||(t[4]=a("h2",{id:"一、编排框架全景图",tabindex:"-1"},[n("一、编排框架全景图 "),a("a",{class:"header-anchor",href:"#一、编排框架全景图","aria-label":'Permalink to "一、编排框架全景图"'},"​")],-1)),(e(),g(s,null,{default:r(()=>[l(d,{id:"mermaid-12",class:"mermaid",graph:"mindmap%0A%20%20root((LLM%20%E7%BC%96%E6%8E%92%E6%A1%86%E6%9E%B6))%0A%20%20%20%20%E9%80%9A%E7%94%A8%E6%A1%86%E6%9E%B6%0A%20%20%20%20%20%20LangChain%0A%20%20%20%20%20%20LlamaIndex%0A%20%20%20%20%20%20Semantic%20Kernel%0A%20%20%20%20Agent%E6%A1%86%E6%9E%B6%0A%20%20%20%20%20%20LangGraph%0A%20%20%20%20%20%20CrewAI%0A%20%20%20%20%20%20AutoGen%0A%20%20%20%20%E8%BD%BB%E9%87%8F%E6%A1%86%E6%9E%B6%0A%20%20%20%20%20%20PydanticAI%0A%20%20%20%20%20%20smolagents%0A%20%20%20%20%20%20Mastra%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=c('<hr><h2 id="二、三大通用框架对比" tabindex="-1">二、三大通用框架对比 <a class="header-anchor" href="#二、三大通用框架对比" aria-label="Permalink to &quot;二、三大通用框架对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>LangChain</th><th>LlamaIndex</th><th>Semantic Kernel</th></tr></thead><tbody><tr><td><strong>开发者</strong></td><td>LangChain Inc</td><td>LlamaIndex Inc</td><td>微软</td></tr><tr><td><strong>语言</strong></td><td>Python / JS</td><td>Python / TS</td><td>C# / Python / Java</td></tr><tr><td><strong>核心定位</strong></td><td>通用 LLM 编排</td><td>数据索引与检索</td><td>企业级 AI 编排</td></tr><tr><td><strong>RAG 能力</strong></td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td></tr><tr><td><strong>Agent 能力</strong></td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐</td></tr><tr><td><strong>企业特性</strong></td><td>LangSmith 监控</td><td>数据连接器丰富</td><td>Azure 集成、安全合规</td></tr><tr><td><strong>学习曲线</strong></td><td>中等</td><td>较低</td><td>中等</td></tr></tbody></table><hr><h2 id="三、各框架擅长领域" tabindex="-1">三、各框架擅长领域 <a class="header-anchor" href="#三、各框架擅长领域" aria-label="Permalink to &quot;三、各框架擅长领域&quot;">​</a></h2><table tabindex="0"><thead><tr><th>框架</th><th>最擅长</th><th>不足</th></tr></thead><tbody><tr><td><strong>LangChain</strong></td><td>复杂 Agent 工作流、多工具编排</td><td>抽象层多，调试困难</td></tr><tr><td><strong>LlamaIndex</strong></td><td>文档解析、数据索引、高级 RAG</td><td>Agent 能力弱</td></tr><tr><td><strong>Semantic Kernel</strong></td><td>企业级集成（Azure/Office）、多语言</td><td>社区生态较小</td></tr><tr><td><strong>LangGraph</strong></td><td>有状态多步 Agent 工作流</td><td>学习曲线陡峭</td></tr><tr><td><strong>CrewAI</strong></td><td>角色驱动的多 Agent 协作</td><td>灵活性受限</td></tr><tr><td><strong>AutoGen</strong></td><td>对话驱动的多 Agent 协作</td><td>调试复杂</td></tr><tr><td><strong>PydanticAI</strong></td><td>结构化输出 + 类型安全</td><td>功能较基础</td></tr></tbody></table><hr><h2 id="四、多框架组合策略" tabindex="-1">四、多框架组合策略 <a class="header-anchor" href="#四、多框架组合策略" aria-label="Permalink to &quot;四、多框架组合策略&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">最佳实践</p><p>不要锁定单一框架。根据场景选择最合适的框架，多框架组合是生产环境的常态。</p></div><table tabindex="0"><thead><tr><th>组合方案</th><th>适用场景</th><th>说明</th></tr></thead><tbody><tr><td><strong>LlamaIndex（检索） + LangChain（编排）</strong></td><td>复杂 RAG + Agent</td><td>LlamaIndex 做文档处理，LangChain 做编排</td></tr><tr><td><strong>PydanticAI（输出） + 向量数据库（检索）</strong></td><td>轻量 RAG</td><td>极简组合</td></tr><tr><td><strong>CrewAI（角色） + LangChain（工具）</strong></td><td>多角色协作</td><td>CrewAI 做分工，LangChain 做工具链</td></tr><tr><td><strong>LangGraph（工作流） + OpenAI SDK（模型）</strong></td><td>复杂工作流</td><td>LangGraph 管流程，OpenAI SDK 管模型</td></tr></tbody></table><hr><h2 id="五、2026-年趋势" tabindex="-1">五、2026 年趋势 <a class="header-anchor" href="#五、2026-年趋势" aria-label="Permalink to &quot;五、2026 年趋势&quot;">​</a></h2><ol><li><strong>从重型到轻型</strong>：开发者从 LangChain 向 PydanticAI/smolagents 等轻量框架迁移</li><li><strong>MCP 标准化</strong>：工具调用统一到 MCP 协议，降低框架锁定</li><li><strong>可观测性成标配</strong>：LangSmith、Weave、Phoenix 等观测工具普及</li><li><strong>TypeScript 生态崛起</strong>：Mastra 等 TS 框架吸引全栈开发者</li></ol><hr><h2 id="六、面试高频题" tabindex="-1">六、面试高频题 <a class="header-anchor" href="#六、面试高频题" aria-label="Permalink to &quot;六、面试高频题&quot;">​</a></h2><h3 id="q1-langchain-和-llamaindex-的核心区别是什么-如何选择" tabindex="-1">Q1: LangChain 和 LlamaIndex 的核心区别是什么？如何选择？ <a class="header-anchor" href="#q1-langchain-和-llamaindex-的核心区别是什么-如何选择" aria-label="Permalink to &quot;Q1: LangChain 和 LlamaIndex 的核心区别是什么？如何选择？&quot;">​</a></h3><p><strong>详细答案：</strong> 我们项目两个框架都在用，现在分工很明确。LangChain 做编排层——对话路由、Agent 决策、Memory 管理、SSE 流式推送，所有需要&quot;控流程&quot;的逻辑都在它手里。LlamaIndex 专门做数据处理——加载文档、建索引、做检索策略，我们知识库 5 万篇文档的索引和检索全是它在扛。如果硬要一句话总结：LangChain 像是一个乐高底板，你可以把各种组件往上拼；LlamaIndex 更像是一台精密的文档处理机，插上电源就能高效运转。</p><p>有个实际案例能说明差别。我们的知识库 QA 需要跨多个产品线检索（比如手机和耳机两个品类可能有不同政策），用 LangChain 裸写的话要自己管理多次检索、结果合并、排序，代码量很大。LlamaIndex 的 <code>SubQuestionQueryEngine</code> 直接一行配置就搞定了——它自动把&quot;手机和耳机的退货政策有什么不同？&quot;拆成两个子问题分别检索然后汇总。但反过来，检索完成后用户开始追问细节、要改订单、要退款，这些交互式的多轮操作 LlamaIndex 就显得很吃力，还是得切回 LangChain 的 Agent 来处理。所以选框架的核心是看你的主要场景：以检索为主选 LlamaIndex，以编排为主选 LangChain，两者都需要就组合用。2025 年之后一个明显趋势是，很多简单项目两个都不用，直接裸 SDK 加个向量库就行了。</p><h3 id="q2-langchain-的优缺点是什么-什么时候不适合用-langchain" tabindex="-1">Q2: LangChain 的优缺点是什么？什么时候不适合用 LangChain？ <a class="header-anchor" href="#q2-langchain-的优缺点是什么-什么时候不适合用-langchain" aria-label="Permalink to &quot;Q2: LangChain 的优缺点是什么？什么时候不适合用 LangChain？&quot;">​</a></h3><p><strong>详细答案：</strong> 我们项目用 LangChain 0.3.x 搭了整个客服系统，说实话优缺点都体验得很透彻。生态方面，LangChain 确实碾压——我们需要对接 Milvus、PostgreSQL、Redis、ES，全有现成的集成，不用写胶水代码。当 OpenAI 推出 function calling 之后，LangChain 不到两周就封好了 <code>create_openai_tools_agent</code>，我们直接迁移，业务代码几乎没动。社区也强，有一次 <code>ConversationSummaryBufferMemory</code> 序列化出 bug，GitHub issue 一搜就有 workaround。</p><p>但吐槽的点也不少。版本升级是最大的痛——我们从 0.1 升到 0.2 那次，<code>initialize_agent</code> 被砍了，所有 Agent 代码重写，折腾了一周多。抽象层也深，有一次 debug callback 没触发，追了四层调用栈才发现是 <code>RunnableConfig</code> 传参问题，用裸 SDK 两分钟就发现的事在 LangChain 里搞了一下午。所以我们现在定了规矩：简单场景一律不用框架——我们有个内部文本分类小工具，开始也用 LangChain，后来去掉框架直接用 <code>openai.chat.completions.create</code>，代码量直接砍半。适合用 LangChain 的场景是：多 Agent 协作、复杂工具编排、有状态的多步工作流；不适合的场景是：简单问答、固定格式输出、批处理、团队不熟悉 LangChain 的项目。</p><h3 id="q3-轻量框架-pydanticai-和重型框架-langchain-如何选择" tabindex="-1">Q3: 轻量框架（PydanticAI）和重型框架（LangChain）如何选择？ <a class="header-anchor" href="#q3-轻量框架-pydanticai-和重型框架-langchain-如何选择" aria-label="Permalink to &quot;Q3: 轻量框架（PydanticAI）和重型框架（LangChain）如何选择？&quot;">​</a></h3><p><strong>详细答案：</strong> 我们团队去年做了一个内部工具，两个项目用了不同框架，对比很直观。A 项目是客服主系统，多 Agent、多工具、复杂路由，选了 LangChain——虽然抽象多，但编排能力确实强，RunnableBranch 一行代码就能做意图路由，AgentExecutor 自动管理执行循环，如果不选 LangChain 我们自己写这些基础设施至少两个月。B 项目是内部的&quot;周报自动生成器&quot;，需求很简单：读 Jira API -&gt; 拼 Prompt -&gt; 调 GPT-4o-mini 生成周报。一开始跟着主项目也用 LangChain，后来发现一层层装配链件的代码比业务逻辑还多，果断换成了 PydanticAI，整功能从 150 行减到 60 行。</p><p>我的判断标准很简单：画一下你的系统流程图，如果超过 3 个分支、需要工具调用、有状态管理、有复杂的对话路由——用 LangChain 或 LangGraph 这类重型框架是值的；如果只是&quot;调模型做个分类/翻译/摘要&quot;，裸 SDK 或者 PydanticAI 完全够。2025-2026 年的一个趋势是&quot;往轻量走&quot;，很多人从 LangChain 迁出去了，因为大多数实际项目真没必要用那么重的框架。另外，团队的熟悉程度也是个硬约束——我们组新来的两个前端背景的同事，上手 PydanticAI 只用了两天，LangChain 花了两周还没搞明白 AgentExecutor 的执行循环。</p><h3 id="q4-多框架组合的常见方案有哪些" tabindex="-1">Q4: 多框架组合的常见方案有哪些？ <a class="header-anchor" href="#q4-多框架组合的常见方案有哪些" aria-label="Permalink to &quot;Q4: 多框架组合的常见方案有哪些？&quot;">​</a></h3><p><strong>详细答案：</strong> 说实话，生产环境只用单一框架的项目很少——我们自己的系统就是&quot;LlamaIndex + LangChain + PydanticAI&quot;三件套组合。LlamaIndex 管知识库检索（5 万篇文档的索引、SubQuestionQueryEngine 子问题拆分、CrossEncoder Rerank），LangChain 管对话编排和 Agent 决策，PydanticAI 管结构化输出（订单信息抽取、工单分类）。每个组件做自己最擅长的事，接口用 FastAPI 兜底。</p><p>其他常见组合我也见过。一个是&quot;PydanticAI + 向量数据库&quot;的轻量 RAG 方案——有家做 SaaS 的朋友就用这套搭了个 FAQ 系统，总共不到 500 行代码，性能很好，检索延迟稳定在 300ms。另一个是&quot;LangGraph + OpenAI SDK&quot;的方案——有个做自动化运维的团队用 LangGraph 定义工作流（有分支、有回退、有状态持久化），但模型调用直接用 OpenAI SDK 不用 LangChain 的 LLM 封装，理由是&quot;LangChain 的 ChatOpenAI 包装层在某些边界情况下会把流式中断掉&quot;。我觉得选择组合的核心不是&quot;哪个框架最流行&quot;，而是&quot;你的每个子系统最适合什么工具&quot;——别因为 LangChain 能检索就硬用它做 RAG，也别因为 LlamaIndex 能调 LLM 就硬用它做 Agent。</p><h3 id="q5-2026-年编排框架的发展趋势是什么" tabindex="-1">Q5: 2026 年编排框架的发展趋势是什么？ <a class="header-anchor" href="#q5-2026-年编排框架的发展趋势是什么" aria-label="Permalink to &quot;Q5: 2026 年编排框架的发展趋势是什么？&quot;">​</a></h3><p><strong>详细答案：</strong> 从我们团队和周边圈子的动向来看，几个趋势很明显。第一是&quot;去重框架化&quot;——去年下半年开始，GitHub 上越来越多项目直接甩掉框架用裸 SDK。我们自己的几个内部小工具也从 LangChain 迁出去了。不是 LangChain 不好，是大多数场景确实用不上那么重的编排能力——一个分类接口几十行 OpenAI SDK 就搞定了，为什么还要引入 80MB 的依赖？</p><p>第二是 MCP（Model Context Protocol）标准化。这是个好东西——以前你写的工具绑定在 LangChain 的 @tool 装饰器上，换框架就得重写。MCP 把工具调用接口标准化之后，工具可以跨框架复用。我们最近在试把内部几个 gRPC 服务包装成 MCP Server，这样不管上层用 LangChain 还是以后换别的框架，工具层不用动。第三是可观测性从 nice-to-have 变成 must-have——我们 Prometheus + Grafana 那一套，每个 LLM 调用的延迟、Token 消耗、错误率都有 Dashboard，没有这套东西跑生产就是盲飞。第四是 TypeScript 生态在发力，Mastra 这类框架让前端全栈可以直接用 TS 写 Agent，虽然生态还没 Python 成熟，但势头很猛。总的来说，2026 年框架在&quot;做减法&quot;而不是做加法。</p><h3 id="q6-semantic-kernel-和-langchain-的定位差异是什么-企业级场景如何选择" tabindex="-1">Q6: Semantic Kernel 和 LangChain 的定位差异是什么？企业级场景如何选择？ <a class="header-anchor" href="#q6-semantic-kernel-和-langchain-的定位差异是什么-企业级场景如何选择" aria-label="Permalink to &quot;Q6: Semantic Kernel 和 LangChain 的定位差异是什么？企业级场景如何选择？&quot;">​</a></h3><p><strong>详细答案：</strong> 我没在生产环境深度用过 Semantic Kernel，但调研过，也和微软的兄弟聊过，理解它的定位。SK 的核心差异就一点：它是&quot;微软生态的 AI 编排框架&quot;，如果你家基础设施全在 Azure 上——Azure OpenAI、Cognitive Search、Functions ——SK 几乎是零配置集成。LangChain 更像&quot;中立第三方&quot;，什么云都能接但都不够深。SK 用 Planner 概念做任务规划，LangChain 用 Chain/Agent；SK 强大在企业级特性——安全、合规、审计开箱就有，LangChain 强大在社区生态和 AI 工具的丰富度。</p><p>企业选型的话，我的经验法则是：如果公司已经在 Azure 上跑着，或者技术栈是 .NET/JAVA（SK 原生支持 C# 和 Java），那 SK 是更自然的选择，Azure 的技术支持也能兜底。如果公司是多云、混合云，或者需要快速试错、灵活切换模型（今天 OpenAI 明天 Claude），那 LangChain 更灵活。我们当时也纠结过要不要上 SK，但因为团队 Python 为主、基础设施在阿里云上、模型除了 OpenAI 还要接 Qwen 和 DeepSeek，LangChain 的灵活性对我们更重要。另外说句实话：SK 的社区活跃度和 AI 前沿跟进速度还是比不上 LangChain——比如 OpenAI 的 structured outputs 出来后 LangChain 一周就适配了，SK 的节奏明显慢半拍。</p>',33))])}const S=o(u,[["render",L]]);export{I as __pageData,S as default};
